const GlassCard = ({ children, style = {}, hover3d = true, glow = false }) => {
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const [hovered, setHovered] = useState(false);
  const handleMove = (e) => {
    if (!hover3d) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 16;
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * -16;
    setTilt({ x, y });
  };
  return (
    <div
      onMouseMove={handleMove}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setTilt({ x: 0, y: 0 }); setHovered(false); }}
      style={{
        background: T.cardBg,
        border: `1px solid ${hovered && glow ? T.gold + "55" : T.glassBorder}`,
        borderRadius: 20,
        backdropFilter: "blur(20px)",
        transform: `perspective(1000px) rotateY(${tilt.x}deg) rotateX(${tilt.y}deg) translateZ(${hovered ? 4 : 0}px)`,
        transition: "transform 0.15s ease, border-color 0.3s ease, box-shadow 0.3s ease",
        willChange: "transform",
        boxShadow: hovered && glow ? `0 8px 40px ${T.gold}22, 0 0 0 1px ${T.gold}11` : "none",
        ...style,
      }}
    >{children}</div>
  );
};

