  const [posting, setPosting] = useState(false);
  const ADMIN_PASSWORD = "deepalli2025";
 const postEvent = async () => {
  if (!newEvent.title || !newEvent.date) {
    alert("Please fill in Title and Date");
    return;
  }
  setPosting(true);
  try {
    await addDoc(collection(db, "events"), {
      title: newEvent.title,
      date: newEvent.date,
      time: newEvent.time,
      location: newEvent.location,
      description: newEvent.description,
      type: newEvent.type,
      createdAt: serverTimestamp(),
    });
    await loadEvents();
    setNewEvent({ title: "", date: "", time: "", location: "", description: "", type: "Sound Bath" });
    alert("Event saved successfully!");
  } catch(e) {
    console.error("Save failed:", e.message);
    alert("Error: " + e.message);
  }
  setPosting(false);
};
  useEffect(() => { loadEvents(); }, []);

 const loadEvents = async () => {
  setLoading(true);
  if (!db) {
    setEvents([
      { id: "1", title: "Full Moon Sound Bath", date: "2025-02-12", time: "7:00 PM", location: "Ludhiana, Punjab", type: "Sound Bath", description: "A powerful group healing ceremony." },
    ]);
    setLoading(false);
    return;
  }
  try {
    // Try WITHOUT orderBy first (orderBy needs an index)
    const snap = await getDocs(collection(db, "events"));
    console.log("Total docs found:", snap.size); // Check browser console
    
    if (snap.empty) {
      console.log("Collection is empty or no permission");
      setEvents([]);
    } else {
      const data = snap.docs.map(d => {
        console.log("Event found:", d.id, d.data()); // See each event
        return { id: d.id, ...d.data() };
      });
      // Sort manually instead of using orderBy
      data.sort((a, b) => (a.date > b.date ? 1 : -1));
      setEvents(data);
    }
  } catch(e) {
    console.error("Firebase error:", e.message); // See exact error
    setEvents([]); // Show empty instead of crashing
  }
  setLoading(false);
};

  const deleteEvent = async (id) => {
  if (!window.confirm("Delete this event?")) return;
  if (!db) {
    setEvents(prev => prev.filter(e => e.id !== id));
    return;
  }
  try {
    const { deleteDoc, doc } = await import("firebase/firestore");
    await deleteDoc(doc(db, "events", id));
    await loadEvents();
  } catch(e) { console.error(e); }
};

